/**
 * Zustand Adapter for BYOS
 *
 * This adapter integrates with existing Zustand stores via a slice pattern.
 * It is client-only and does not support SSR.
 */

"use client";

import { useMemo, useRef } from "react";
import type { StoreApi } from "zustand";
import type { InternalStoreAdapter } from "../../adapter/types";
import { getSchemaDefaults } from "../../schema/serialization";
import type { SchemaDefinition, StoreSnapshot } from "../../schema/types";
import { getFilterSliceKeys } from "./slice";
import type { ZustandAdapterOptions } from "./types";

export type {
  ZustandAdapterOptions,
  FilterSlice,
  FilterSliceState,
  FilterSliceActions,
} from "./types";
export {
  createFilterSlice,
  getFilterSliceKeys,
  getFilterSliceFromState,
} from "./slice";

/**
 * Create a Zustand adapter from an existing store
 *
 * @example
 * ```typescript
 * import { create } from 'zustand';
 * import { createFilterSlice, useZustandAdapter } from '@/lib/store/adapters/zustand';
 *
 * const schema = createSchema({
 *   regions: field.array(field.string()).default([]),
 *   host: field.string(),
 * });
 *
 * // Create store with filter slice
 * const useAppStore = create((set, get) => ({
 *   user: null,
 *   ...createFilterSlice(schema.definition, 'my-table', set, get),
 * }));
 *
 * // In component
 * function MyComponent() {
 *   const adapter = useZustandAdapter(useAppStore, schema.definition, { id: 'my-table' });
 *   return (
 *     <DataTableStoreProvider adapter={adapter}>
 *       <DataTable />
 *     </DataTableStoreProvider>
 *   );
 * }
 * ```
 */
export function useZustandAdapter<
  TStore extends Record<string, unknown>,
  TFilters extends Record<string, unknown>,
>(
  useStore: {
    (): TStore;
    getState: () => TStore;
    subscribe: (
      listener: (state: TStore, prevState: TStore) => void,
    ) => () => void;
  },
  schema: SchemaDefinition,
  options: ZustandAdapterOptions<TFilters>,
): InternalStoreAdapter<TFilters> {
  const { id, initialState } = options;
  const keys = getFilterSliceKeys(id);
  const defaults = useMemo(
    () => getSchemaDefaults(schema) as TFilters,
    [schema],
  );

  const versionRef = useRef(0);

  // Cache server snapshot to avoid infinite loop with useSyncExternalStore
  const serverSnapshotRef = useRef<StoreSnapshot<TFilters>>({
    state: { ...defaults, ...initialState } as TFilters,
    version: 0,
  });

  const adapter = useMemo<InternalStoreAdapter<TFilters>>(() => {
    const storeApi = useStore as unknown as StoreApi<TStore>;

    return {
      subscribe(listener: () => void) {
        return storeApi.subscribe(() => {
          versionRef.current++;
          listener();
        });
      },

      getSnapshot(): StoreSnapshot<TFilters> {
        const state = storeApi.getState();
        const filters = (state[keys.state] as TFilters) || defaults;
        return {
          state: filters,
          version: versionRef.current,
        };
      },

      // Zustand adapter is client-only, return cached snapshot for SSR
      getServerSnapshot(): StoreSnapshot<TFilters> {
        return serverSnapshotRef.current;
      },

      setState(partial: Partial<TFilters>) {
        const state = storeApi.getState();
        const setFilters = state[keys.setFilters] as
          | ((partial: Partial<TFilters>) => void)
          | undefined;

        if (setFilters) {
          setFilters(partial);
        } else {
          // Fallback: direct state update if slice actions not found
          const current = (state[keys.state] as TFilters) || defaults;
          (storeApi as unknown as StoreApi<Record<string, unknown>>).setState({
            [keys.state]: { ...current, ...partial },
          });
        }
      },

      setField<K extends keyof TFilters>(key: K, value: TFilters[K]) {
        this.setState({ [key]: value } as unknown as Partial<TFilters>);
      },

      reset(fields?: (keyof TFilters)[]) {
        const state = storeApi.getState();
        const resetFilters = state[keys.resetFilters] as
          | ((fields?: (keyof TFilters)[]) => void)
          | undefined;

        if (resetFilters) {
          resetFilters(fields);
        } else {
          // Fallback: direct reset
          if (fields) {
            const resetPartial: Partial<TFilters> = {};
            for (const field of fields) {
              resetPartial[field] = defaults[field];
            }
            this.setState(resetPartial);
          } else {
            (storeApi as unknown as StoreApi<Record<string, unknown>>).setState(
              {
                [keys.state]: defaults,
              },
            );
          }
        }
      },

      pause() {
        const state = storeApi.getState();
        const pauseFilters = state[keys.pauseFilters] as
          | (() => void)
          | undefined;

        if (pauseFilters) {
          pauseFilters();
        } else {
          (storeApi as unknown as StoreApi<Record<string, unknown>>).setState({
            [keys.paused]: true,
          });
        }
      },

      resume() {
        const state = storeApi.getState();
        const resumeFilters = state[keys.resumeFilters] as
          | (() => void)
          | undefined;

        if (resumeFilters) {
          resumeFilters();
        } else {
          const pending = state[keys.pending] as Partial<TFilters> | null;
          (storeApi as unknown as StoreApi<Record<string, unknown>>).setState({
            [keys.paused]: false,
            [keys.pending]: null,
          });

          if (pending) {
            this.setState(pending);
          }
        }
      },

      isPaused() {
        const state = storeApi.getState();
        return (state[keys.paused] as boolean) || false;
      },

      destroy() {
        // Nothing to clean up for Zustand adapter
      },

      getTableId() {
        return id;
      },

      getSchema() {
        return schema;
      },

      getDefaults() {
        return defaults;
      },
    };
  }, [useStore, schema, id, defaults, initialState, keys]);

  return adapter;
}

/**
 * Zustand Adapter Types
 */

import type { StoreApi } from "zustand";
import type { CreateAdapterOptions } from "../../adapter/types";

/**
 * Zustand-specific adapter options
 */
export interface ZustandAdapterOptions<T extends Record<string, unknown>>
  extends CreateAdapterOptions<T> {
  // Zustand adapter uses existing store integration, no additional options needed
}

/**
 * State shape for the filter slice in a Zustand store
 */
export interface FilterSliceState<T extends Record<string, unknown>> {
  filters: T;
  filtersPaused: boolean;
  filtersPending: Partial<T> | null;
}

/**
 * Actions for the filter slice
 */
export interface FilterSliceActions<T extends Record<string, unknown>> {
  setFilters: (partial: Partial<T>) => void;
  resetFilters: (fields?: (keyof T)[]) => void;
  pauseFilters: () => void;
  resumeFilters: () => void;
}

/**
 * Complete filter slice type
 */
export type FilterSlice<T extends Record<string, unknown>> =
  FilterSliceState<T> & FilterSliceActions<T>;

/**
 * Zustand store API type for adapter
 */
export type ZustandStoreApi<T> = StoreApi<T>;

/**
 * Zustand Slice Creator for Filter State
 *
 * Creates a namespaced slice for filter state that can be added to existing Zustand stores.
 */

import { getSchemaDefaults } from "../../schema/serialization";
import type { SchemaDefinition } from "../../schema/types";
import type { FilterSlice } from "./types";

/**
 * Create state keys for a filter slice (namespaced by table ID)
 */
export function getFilterSliceKeys(tableId: string) {
  return {
    state: `filters_${tableId}` as const,
    paused: `filters_${tableId}_paused` as const,
    pending: `filters_${tableId}_pending` as const,
    setFilters: `setFilters_${tableId}` as const,
    resetFilters: `resetFilters_${tableId}` as const,
    pauseFilters: `pauseFilters_${tableId}` as const,
    resumeFilters: `resumeFilters_${tableId}` as const,
  };
}

/**
 * Type helper for getting the slice keys type
 */
export type FilterSliceKeys = ReturnType<typeof getFilterSliceKeys>;

/**
 * Create a filter slice for a Zustand store
 *
 * @example
 * ```typescript
 * import { create } from 'zustand';
 * import { createFilterSlice } from '@/lib/store/adapters/zustand';
 *
 * const schema = createSchema({
 *   regions: field.array(field.string()).default([]),
 *   host: field.string(),
 * });
 *
 * const useStore = create((set, get) => ({
 *   // Your existing state
 *   user: null,
 *   theme: 'light',
 *
 *   // Add filter slice
 *   ...createFilterSlice(schema.definition, 'my-table', set, get),
 * }));
 * ```
 */
export function createFilterSlice<T extends Record<string, unknown>>(
  schema: SchemaDefinition,
  tableId: string,
  set: (
    partial:
      | Record<string, unknown>
      | ((state: Record<string, unknown>) => Record<string, unknown>),
  ) => void,
  get: () => Record<string, unknown>,
  initialState?: Partial<T>,
): Record<string, unknown> {
  const keys = getFilterSliceKeys(tableId);
  const defaults = getSchemaDefaults(schema) as T;
  const initial = { ...defaults, ...initialState };

  return {
    // State
    [keys.state]: initial,
    [keys.paused]: false,
    [keys.pending]: null,

    // Actions
    [keys.setFilters]: (partial: Partial<T>) => {
      const state = get();
      const isPaused = state[keys.paused] as boolean;

      if (isPaused) {
        const pending = (state[keys.pending] as Partial<T> | null) || {};
        set({ [keys.pending]: { ...pending, ...partial } });
        return;
      }

      const current = state[keys.state] as T;
      set({ [keys.state]: { ...current, ...partial } });
    },

    [keys.resetFilters]: (fields?: (keyof T)[]) => {
      const state = get();
      const current = state[keys.state] as T;

      if (fields) {
        const resetPartial: Partial<T> = {};
        for (const field of fields) {
          resetPartial[field] = defaults[field];
        }
        set({ [keys.state]: { ...current, ...resetPartial } });
      } else {
        set({ [keys.state]: defaults });
      }
    },

    [keys.pauseFilters]: () => {
      set({ [keys.paused]: true });
    },

    [keys.resumeFilters]: () => {
      const state = get();
      const pending = state[keys.pending] as Partial<T> | null;

      set({ [keys.paused]: false, [keys.pending]: null });

      if (pending) {
        const current = state[keys.state] as T;
        set({ [keys.state]: { ...current, ...pending } });
      }
    },
  };
}

/**
 * Get filter slice from a Zustand store state
 */
export function getFilterSliceFromState<T extends Record<string, unknown>>(
  state: Record<string, unknown>,
  tableId: string,
): FilterSlice<T> | null {
  const keys = getFilterSliceKeys(tableId);

  if (!(keys.state in state)) {
    return null;
  }

  return {
    filters: state[keys.state] as T,
    filtersPaused: state[keys.paused] as boolean,
    filtersPending: state[keys.pending] as Partial<T> | null,
    setFilters: state[keys.setFilters] as (partial: Partial<T>) => void,
    resetFilters: state[keys.resetFilters] as (fields?: (keyof T)[]) => void,
    pauseFilters: state[keys.pauseFilters] as () => void,
    resumeFilters: state[keys.resumeFilters] as () => void,
  };
}
